# 1. Wyciągnij wszystkie liczby z <li class="numbers_in_list">
nums = re.findall(r'<li class="numbers_in_list\s*"\s*>(\d+)', html)

# 2. Podziel na wiersze po 6 liczb (jedno losowanie = 6 liczb)
rows = [nums[i:i+6] for i in range(0, len(nums), 6)]

print(f"Znaleziono {len(nums)} liczb, {len(rows)} wierszy po 6 liczb")
print(f"Pierwsze 3 wiersze: {rows[:3]}")

# 3. Zapisz do CSV dla LibreOffice Calc
with open('lotto_wyniki.csv', 'w', newline='', encoding='utf-8') as f:
    writer = csv.writer(f, delimiter=';')  # średnik dla polskiej wersji Calc
    for row in rows:
        writer.writerow(row)

print("\n✅ Plik 'lotto_wyniki.csv' gotowy!")
